pub async fn get_user_by_name(pool: &sqlx::PgPool, name: &str) -> Result<GetUserByNameRow, sqlx::Error> {
    sqlx::query_as!(GetUserByNameRow, "SELECT id, name, email FROM users WHERE name = $1", name)
        .fetch_one(pool)
        .await
}

